import { Request, Response } from 'aether';
import { parseBody } from '/lib/validate';
import { ok, err, Result } from '/lib/result';
import { query } from '/lib/db';
import { z } from 'zod';
import crypto from 'crypto'; // For generating secure tokens

// Assume a simple email sending utility exists
// In a real app, this would integrate with an email service (e.g., SendGrid, Mailgun)
async function sendEmail(to: string, subject: string, body: string): Promise<Result<true, Error>> {
  console.log(`Sending email to: ${to}`);
  console.log(`Subject: ${subject}`);
  console.log(`Body: ${body}`);
  // Simulate email sending delay
  await new Promise(resolve => setTimeout(resolve, 500));
  // In a real application, you'd handle potential email sending errors here
  return ok(true);
}

// Schema for the request body
const passwordResetRequestSchema = z.object({
  email: z.string().email('Invalid email address'),
});

// Generate a secure, URL-safe token
function generateSecureToken(): string {
  return crypto.randomBytes(32).toString('hex'); // 64 characters long
}

export default async function passwordResetRequest(req: Request): Promise<Response> {
  const bodyResult = await parseBody(req, passwordResetRequestSchema);

  if (bodyResult.isErr()) {
    // For security, we still return 200 OK even on validation errors
    // to avoid revealing information about expected input formats.
    // Log the error internally for debugging.
    console.warn('Password reset request body validation failed:', bodyResult.error);
    return new Response(null, { status: 200 });
  }

  const { email } = bodyResult.value;

  // Look up the user by email
  const userQueryResult = await query<{ id: string }>('SELECT id FROM users WHERE email = $1', [email]);

  if (userQueryResult.isErr()) {
    console.error('Database error during user lookup for password reset:', userQueryResult.error);
    // System error, but for security, still return 200 OK to the client
    return new Response(null, { status: 200 });
  }

  const user = userQueryResult.value[0];

  if (user) {
    // User found, proceed to generate and store token
    const token = generateSecureToken();
    const expiresAt = new Date(Date.now() + 3600 * 1000); // Token valid for 1 hour

    const insertTokenResult = await query(
      `INSERT INTO password_reset_tokens (user_id, token, expires_at)
       VALUES ($1, $2, $3)`,
      [user.id, token, expiresAt.toISOString()]
    );

    if (insertTokenResult.isErr()) {
      console.error('Database error inserting password reset token:', insertTokenResult.error);
      // System error, but for security, still return 200 OK to the client
      return new Response(null, { status: 200 });
    }

    // Construct the reset link (replace with your actual frontend URL)
    const resetLink = `http://localhost:3000/reset-password?token=${token}`; // TODO: Use actual domain from config

    const emailResult = await sendEmail(
      email,
      'Password Reset Request for my-app',
      `You have requested a password reset for your my-app account.
      Please click on the following link to reset your password: ${resetLink}

      This link will expire in 1 hour. If you did not request this, please ignore this email.`
    );

    if (emailResult.isErr()) {
      console.error('Failed to send password reset email:', emailResult.error);
      // Log the error, but still return 200 OK to the client
    }
  } else {
    // User not found. For security, do nothing and still return 200 OK.
    console.log(`Password reset requested for unknown email: ${email}. Returning 200 OK.`);
  }

  // Always return 200 OK to prevent user enumeration, regardless of whether the email exists
  // or if there were internal errors (which should be logged).
  return new Response(null, { status: 200 });
}
